// src/hooks/useSerialSensor.js
import { useState, useCallback, useRef, useEffect } from 'react';
import WebSerialService from '../services/webSerialService';

export const useSerialSensor = () => {
    const [status, setStatus] = useState({ connected: false });
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(null);
    const serialServiceRef = useRef(null);
    const isConnectingRef = useRef(false);

    // Check for existing connection on mount
    useEffect(() => {
        const savedConnection = localStorage.getItem('sensorConnected');
        if (savedConnection === 'true') {
            // Attempt to restore connection
            connect();
        }
    }, []);

    const connect = useCallback(async () => {
        if (isConnectingRef.current) {
            console.log('Connection already in progress');
            return { success: false, error: 'Connection already in progress' };
        }
        
        if (serialServiceRef.current?.isConnected) {
            console.log('Already connected');
            setStatus({ connected: true });
            return { success: true };
        }
        
        isConnectingRef.current = true;
        setLoading(true);
        setError(null);
        
        try {
            const service = new WebSerialService();
            
            service.on('disconnected', () => {
                setStatus({ connected: false });
                serialServiceRef.current = null;
                localStorage.removeItem('sensorConnected');
                setError('Device disconnected');
            });
            
            const result = await service.connect();
            
            if (result.success) {
                serialServiceRef.current = service;
                setStatus({ connected: true });
                localStorage.setItem('sensorConnected', 'true');
                setError(null);
                return { success: true };
            } else {
                if (result.error?.includes('No port selected') || result.error?.includes('user cancelled')) {
                    setError('No port selected. Please select a port to connect.');
                } else {
                    setError(result.error);
                }
                localStorage.removeItem('sensorConnected');
                return { success: false, error: result.error };
            }
        } catch (err) {
            const errorMsg = err.message || 'Connection failed';
            setError(errorMsg);
            localStorage.removeItem('sensorConnected');
            return { success: false, error: errorMsg };
        } finally {
            setLoading(false);
            isConnectingRef.current = false;
        }
    }, []);

    const disconnect = useCallback(() => {
        if (serialServiceRef.current) {
            serialServiceRef.current.disconnect();
            serialServiceRef.current = null;
            setStatus({ connected: false });
            localStorage.removeItem('sensorConnected');
        }
    }, []);

    const scanFingerprint = useCallback(async () => {
        if (!serialServiceRef.current || !status.connected) {
            throw new Error('Not connected to device');
        }
        
        setLoading(true);
        try {
            return await serialServiceRef.current.scanFingerprint();
        } catch (err) {
            setError(err.message);
            throw err;
        } finally {
            setLoading(false);
        }
    }, [status.connected]);

    const enrollFingerprint = useCallback(async () => {
        if (!serialServiceRef.current || !status.connected) {
            throw new Error('Not connected to device');
        }
        
        setLoading(true);
        try {
            return await serialServiceRef.current.enrollFingerprint();
        } catch (err) {
            setError(err.message);
            throw err;
        } finally {
            setLoading(false);
        }
    }, [status.connected]);

    return {
        status,
        loading,
        error,
        connect,
        disconnect,
        scanFingerprint,
        enrollFingerprint,
        isSerialSupported: !!navigator.serial
    };
};
